from flask import Flask, request, redirect, session, url_for, jsonify
import requests
import secrets
import urllib.parse
import os

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(16))

# Configuration
OIDC_CONFIG = {
    'authorization_endpoint': os.environ.get('OIDC_AUTHORIZATION_ENDPOINT'),
    'token_endpoint': os.environ.get('OIDC_TOKEN_ENDPOINT'),
    'userinfo_endpoint': os.environ.get('OIDC_USERINFO_ENDPOINT'),
    'client_id': os.environ.get('OIDC_CLIENT_ID'),
    'client_secret': os.environ.get('OIDC_CLIENT_SECRET'),
    'redirect_uri': os.environ.get('OIDC_REDIRECT_URI'),
    'issuer': os.environ.get('OIDC_ISSUER')
}

def get_authorization_url():
    params = {
        'response_type': 'id_token',
        'client_id': OIDC_CONFIG['client_id'],
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'scope': 'openid',
        'nonce': secrets.token_urlsafe(32)
    }
    query_string = urllib.parse.urlencode(params)
    return f"{OIDC_CONFIG['authorization_endpoint']}?{query_string}"

@app.route('/')
def index():
    return '<a href="/login">Login with SSO</a>'

@app.route('/login')
def login():
    auth_url = get_authorization_url()
    return redirect(auth_url)

@app.route('/callback')
def callback():
    id_token = request.args.get('id_token')
    if not id_token:
        return "Missing id_token", 400
    
    # Validate token (basic validation)
    try:
        # In production, validate JWT signature and claims
        # This is a simplified version
        token_parts = id_token.split('.')
        if len(token_parts) != 3:
            return "Invalid token format", 400
        
        # Store token in session
        session['id_token'] = id_token
        session['logged_in'] = True
        return redirect('/dashboard')
    except Exception as e:
        return f"Token validation failed: {str(e)}", 400

@app.route('/dashboard')
def dashboard():
    if not session.get('logged_in'):
        return redirect('/login')
    
    return f"Welcome to Admin Dashboard! <a href='/logout'>Logout</a>"

@app.route('/logout')
def logout():
    session.clear()
    return redirect('/')

if __name__ == '__main__':
    app.run(debug=False, ssl_context='adhoc')